  `updated_by_id` int DEFAULT NULL,
  `table_fmt` enum('classic','form') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'classic',
  `mode_num_is` enum('title','item') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'item'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

